```typescript
import { describe, test, expect, mock, beforeEach, afterEach } from 'bun:test';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { CopyButton } from '@/components/copy-button';

describe('CopyButton', () => {
  let mockWriteText: ReturnType<typeof mock>;

  beforeEach(() => {
    console.log('[UNIT:CopyButton] Setting up test');
    mockWriteText = mock(() => Promise.resolve());
    Object.assign(navigator.clipboard, { writeText: mockWriteText });
  });

  afterEach(() => {
    console.log('[UNIT:CopyButton] Cleaning up');
  });

  describe('Rendering', () => {
    test('renders with copy icon by default', () => {
      console.log('[UNIT:CopyButton] Testing default render');
      render(<CopyButton text="test content" />);

      const button = screen.getByRole('button');
      expect(button).toBeInTheDocument();
      expect(button).toHaveAttribute('aria-label', expect.stringMatching(/copy/i));
      console.log('[UNIT:CopyButton] Default render passed');
    });

    test('accepts custom className', () => {
      console.log('[UNIT:CopyButton] Testing custom className');
      render(<CopyButton text="test" className="custom-class" />);

      const button = screen.getByRole('button');
      expect(button).toHaveClass('custom-class');
    });
  });

  describe('Copy Functionality', () => {
    test('copies text to clipboard on click', async () => {
      console.log('[UNIT:CopyButton] Testing clipboard copy');
      const testText = 'curl -fsSL https://example.com | bash';
      render(<CopyButton text={testText} />);

      const button = screen.getByRole('button');
      fireEvent.click(button);

      expect(mockWriteText).toHaveBeenCalledWith(testText);
      console.log('[UNIT:CopyButton] Clipboard copy verified');
    });

    test('shows success state after copy', async () => {
      console.log('[UNIT:CopyButton] Testing success state');
      render(<CopyButton text="test" />);

      const button = screen.getByRole('button');
      fireEvent.click(button);

      await waitFor(() => {
        expect(button).toHaveAttribute('aria-label', expect.stringMatching(/copied/i));
      });
      console.log('[UNIT:CopyButton] Success state verified');
    });

    test('resets to copy state after timeout', async () => {
      console.log('[UNIT:CopyButton] Testing reset timeout');
      render(<CopyButton text="test" resetDelay={100} />);

      const button = screen.getByRole('button');
      fireEvent.click(button);

      // Wait for success state
      await waitFor(() => {
        expect(button).toHaveAttribute('aria-label', expect.stringMatching(/copied/i));
      });

      // Wait for reset
      await waitFor(() => {
        expect(button).toHaveAttribute('aria-label', expect.stringMatching(/copy/i));
      }, { timeout: 200 });

      console.log('[UNIT:CopyButton] Reset timeout verified');
    });

    test('handles clipboard error gracefully', async () => {
      console.log('[UNIT:CopyButton] Testing error handling');
      mockWriteText.mockImplementation(() => Promise.reject(new Error('Permission denied')));

      render(<CopyButton text="test" />);

      const button = screen.getByRole('button');

      // Should not throw
      fireEvent.click(button);

      // Component should still be functional
      expect(button).toBeInTheDocument();
      console.log('[UNIT:CopyButton] Error handling verified');
    });
  });

  describe('Accessibility', () => {
    test('is keyboard accessible', () => {
      console.log('[UNIT:CopyButton] Testing keyboard access');
      render(<CopyButton text="test" />);

      const button = screen.getByRole('button');
      button.focus();

      expect(document.activeElement).toBe(button);

      fireEvent.keyDown(button, { key: 'Enter' });
      expect(mockWriteText).toHaveBeenCalled();

      console.log('[UNIT:CopyButton] Keyboard access verified');
    });
  });
});
```

