  const mockOnSearch = mock((query: string) => {});

  describe('Rendering', () => {
    test('renders search input with placeholder', () => {
      console.log('[UNIT:SearchBar] Testing render');
      render(<ToolSearchBar onSearch={mockOnSearch} />);

      const input = screen.getByPlaceholderText(/search tools/i);
