    test('renders with search icon', () => {
      console.log('[UNIT:SearchBar] Testing search icon');
      render(<ToolSearchBar onSearch={mockOnSearch} />);

      const icon = screen.getByTestId('search-icon');
      expect(icon).toBeInTheDocument();
    });
  });

  describe('Search Behavior', () => {
    test('calls onSearch with debounced input', async () => {
      console.log('[UNIT:SearchBar] Testing debounced search');
      const user = userEvent.setup();
      render(<ToolSearchBar onSearch={mockOnSearch} debounceMs={50} />);

      const input = screen.getByRole('searchbox');
      await user.type(input, 'memory');

      // Should not be called immediately
      expect(mockOnSearch).not.toHaveBeenCalled();

      // Wait for debounce
      await waitFor(() => {
        expect(mockOnSearch).toHaveBeenCalledWith('memory');
      }, { timeout: 100 });

      console.log('[UNIT:SearchBar] Debounce verified');
    });

    test('shows clear button when input has value', async () => {
      console.log('[UNIT:SearchBar] Testing clear button visibility');
      const user = userEvent.setup();
      render(<ToolSearchBar onSearch={mockOnSearch} />);

      // Clear button should not be visible initially
      expect(screen.queryByRole('button', { name: /clear/i })).not.toBeInTheDocument();

      // Type something
      const input = screen.getByRole('searchbox');
      await user.type(input, 'test');

      // Clear button should appear
      expect(screen.getByRole('button', { name: /clear/i })).toBeInTheDocument();

      console.log('[UNIT:SearchBar] Clear button visibility verified');
    });

