### `tests/unit/components/count-up-stat.test.tsx`
```typescript
import { describe, test, expect } from 'bun:test';
import { render, screen, waitFor } from '@testing-library/react';
import { CountUpStat } from '@/components/count-up-stat';

describe('CountUpStat', () => {
  describe('Animation', () => {
    test('animates from 0 to target value', async () => {
      console.log('[UNIT:CountUp] Testing animation');
      render(<CountUpStat value={100} label="Test" />);

      // Initially should show 0 or low number
      const stat = screen.getByText(/\d+/);
      const initialValue = parseInt(stat.textContent || '0');
      expect(initialValue).toBeLessThan(100);

      // Wait for animation to complete
      await waitFor(() => {
        const finalValue = parseInt(screen.getByText(/\d+/).textContent || '0');
        expect(finalValue).toBe(100);
      }, { timeout: 2000 });

      console.log('[UNIT:CountUp] Animation completed');
    });

    test('respects reduced motion preference', () => {
      console.log('[UNIT:CountUp] Testing reduced motion');

      // Mock matchMedia to return reduced motion
      window.matchMedia = (query: string) => ({
        matches: query.includes('reduce'),
        media: query,
        onchange: null,
        addListener: () => {},
        removeListener: () => {},
        addEventListener: () => {},
        removeEventListener: () => {},
        dispatchEvent: () => false,
      });

      render(<CountUpStat value={100} label="Test" />);

      // Should show final value immediately
      expect(screen.getByText('100')).toBeInTheDocument();

      console.log('[UNIT:CountUp] Reduced motion verified');
    });
  });

  describe('Formatting', () => {
    test('handles K suffix correctly', async () => {
      console.log('[UNIT:CountUp] Testing K suffix');
      render(<CountUpStat value={1400} label="Stars" suffix="K" />);

      await waitFor(() => {
        expect(screen.getByText(/1\.4K|1,400/)).toBeInTheDocument();
      }, { timeout: 2000 });
    });
  });
});
